from flask import Flask, request, jsonify, redirect, url_for
import secrets

app = Flask(__name__)

auth_codes = {}
access_tokens = {}

def generate_code():
    return secrets.token_urlsafe(16)

def generate_token():
    return secrets.token_urlsafe(32)

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    user_id = request.args.get('user_id')

    if not client_id or not redirect_uri or not user_id:
        return jsonify({'error': 'Invalid request'}), 400

    code = generate_code()
    auth_codes[code] = user_id

    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    code = request.form.get('code')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not code or not client_id or not client_secret:
        return jsonify({'error': 'Invalid request'}), 400

    user_id = auth_codes.get(code)
    if not user_id:
        return jsonify({'error': 'Invalid authorization code'}), 400

    token = generate_token()
    access_tokens[token] = user_id

    return jsonify({'access_token': token, 'token_type': 'Bearer'})

@app.route('/validate', methods=['POST'])
def validate():
    token = request.form.get('access_token')

    if not token:
        return jsonify({'error': 'Invalid request'}), 400

    user_id = access_tokens.get(token)
    if not user_id:
        return jsonify({'error': 'Invalid token'}), 400

    return jsonify({'user_id': user_id})

